import React, { useState, useEffect, useContext, useCallback } from 'react';
import { 
  Box, Typography, CircularProgress, Alert, Container, Grid, Paper, 
  Avatar, List, ListItem, ListItemIcon, ListItemText, Divider 
} from '@mui/material';
import { Home, Person, ExitToApp, TrendingUp } from '@mui/icons-material';
import { Link as RouterLink, useNavigate } from 'react-router-dom';
import Navbar from '../components/Navbar';
import CreatePost from '../components/CreatePost';
import PostCard from '../components/PostCard';
import { fetchPosts } from '../api';
import { AuthContext } from '../context/AuthContext';

export default function FeedPage() {
  const { user, logout } = useContext(AuthContext);
  const navigate = useNavigate();
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const loadPosts = useCallback(async () => {
    try {
      setError('');
      const { data } = await fetchPosts();
      setPosts(data);
    } catch {
      setError('Failed to load posts. Please refresh.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadPosts();
  }, [loadPosts]);

  const handlePostCreated = (newPost) => {
    setPosts((prev) => [newPost, ...prev]);
  };

  const handlePostUpdated = (updatedPost) => {
    setPosts((prev) => prev.map((p) => (p._id === updatedPost._id ? updatedPost : p)));
  };

  const handlePostDeleted = (deletedId) => {
    setPosts((prev) => prev.filter((p) => p._id !== deletedId));
  };

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <Box sx={{ minHeight: '100vh', background: 'linear-gradient(180deg, #0f0f1a 0%, #0f0f1a 100%)' }}>
      <Navbar />
      <Container maxWidth="lg" sx={{ pt: 4, pb: 8 }}>
        <Grid container spacing={4}>
          {/* Left Sidebar */}
          <Grid item xs={12} md={3} sx={{ display: { xs: 'none', md: 'block' } }}>
            <Box sx={{ position: 'sticky', top: 80 }}>
              <Paper sx={{ p: 3, borderRadius: 4, bgcolor: 'rgba(26,26,46,0.95)', border: '1px solid rgba(108,99,255,0.2)' }}>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, mb: 3 }}>
                  <Avatar sx={{ bgcolor: '#6C63FF', width: 48, height: 48, fontWeight: 700 }}>
                    {user?.username?.[0]?.toUpperCase()}
                  </Avatar>
                  <Box>
                    <Typography variant="subtitle1" fontWeight={700} color="#e5e5ff">
                      {user?.username}
                    </Typography>
                    <Typography variant="caption" color="text.secondary" sx={{ wordBreak: 'break-all' }}>
                      {user?.email}
                    </Typography>
                  </Box>
                </Box>

                <Divider sx={{ borderColor: 'rgba(108,99,255,0.1)', mb: 2 }} />

                <List sx={{ px: 0 }}>
                  <ListItem button component={RouterLink} to="/" sx={{ borderRadius: 2, mb: 1, bgcolor: 'rgba(108,99,255,0.1)' }}>
                    <ListItemIcon sx={{ color: '#6C63FF', minWidth: 40 }}><Home /></ListItemIcon>
                    <ListItemText primary="Home" primaryTypographyProps={{ fontWeight: 600, color: '#e5e5ff' }} />
                  </ListItem>

                  <ListItem button component={RouterLink} to={`/profile/${user?.id}`} sx={{ borderRadius: 2, mb: 1, '&:hover': { bgcolor: 'rgba(108,99,255,0.1)' } }}>
                    <ListItemIcon sx={{ color: '#b0b0cc', minWidth: 40 }}><Person /></ListItemIcon>
                    <ListItemText primary="Profile" primaryTypographyProps={{ fontWeight: 600, color: '#b0b0cc' }} />
                  </ListItem>

                  <ListItem button onClick={handleLogout} sx={{ borderRadius: 2, '&:hover': { bgcolor: 'rgba(255,101,132,0.1)' } }}>
                    <ListItemIcon sx={{ color: '#FF6584', minWidth: 40 }}><ExitToApp /></ListItemIcon>
                    <ListItemText primary="Logout" primaryTypographyProps={{ fontWeight: 600, color: '#FF6584' }} />
                  </ListItem>
                </List>
              </Paper>
            </Box>
          </Grid>

          {/* Center Feed */}
          <Grid item xs={12} md={6}>
            <CreatePost onPostCreated={handlePostCreated} />

            {error && (
              <Alert severity="error" sx={{ mt: 2, borderRadius: 2 }}>{error}</Alert>
            )}

            {loading ? (
              <Box sx={{ display: 'flex', justifyContent: 'center', mt: 6 }}>
                <CircularProgress sx={{ color: '#6C63FF' }} />
              </Box>
            ) : posts.length === 0 ? (
              <Box sx={{ textAlign: 'center', mt: 8 }}>
                <Typography variant="h6" color="text.secondary">No posts yet.</Typography>
                <Typography variant="body2" color="text.secondary" sx={{ mt: 1 }}>
                  Be the first to share something!
                </Typography>
              </Box>
            ) : (
              <Box sx={{ mt: 3, display: 'flex', flexDirection: 'column', gap: 2 }}>
                {posts.map((post) => (
                  <PostCard
                    key={post._id}
                    post={post}
                    currentUserId={user?.id}
                    onPostUpdated={handlePostUpdated}
                    onPostDeleted={handlePostDeleted}
                  />
                ))}
              </Box>
            )}
          </Grid>

          {/* Right Sidebar */}
          <Grid item xs={12} md={3} sx={{ display: { xs: 'none', md: 'block' } }}>
            <Box sx={{ position: 'sticky', top: 80 }}>
              <Paper sx={{ p: 3, borderRadius: 4, bgcolor: 'rgba(26,26,46,0.95)', border: '1px solid rgba(108,99,255,0.2)' }}>
                <Typography variant="subtitle1" fontWeight={700} color="#e5e5ff" sx={{ mb: 2, display: 'flex', alignItems: 'center', gap: 1 }}>
                  <TrendingUp sx={{ color: '#FF6584' }} />
                  Trending Topics
                </Typography>

                <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1.5 }}>
                  {['#ReactJS', '#MERNStack', '#WebDev', '#ConnectSphere', '#UIUX'].map((tag) => (
                    <Typography key={tag} variant="body2" color="#6C63FF" sx={{ cursor: 'pointer', fontWeight: 500, '&:hover': { textDecoration: 'underline' } }}>
                      {tag}
                    </Typography>
                  ))}
                </Box>

                <Divider sx={{ borderColor: 'rgba(108,99,255,0.1)', my: 2 }} />

                <Typography variant="caption" color="text.secondary" sx={{ display: 'block', textAlign: 'center' }}>
                  © {new Date().getFullYear()} ConnectSphere
                </Typography>
              </Paper>
            </Box>
          </Grid>

        </Grid>
      </Container>
    </Box>
  );
}
